package com.loosenotes.model;

import java.time.Instant;

/**
 * Represents a share link token for a note.
 *
 * SSEM notes:
 * - Authenticity: token is a cryptographically random value generated by SecureTokenUtil.
 * - Integrity: noteId ties the link to exactly one note; revocation deletes the row.
 */
public class ShareLink {

    private long id;
    private long noteId;
    /** 32-byte URL-safe hex token. Never guessable. */
    private String token;
    private Instant createdAt;

    public ShareLink() {}

    public long getId() { return id; }
    public void setId(long id) { this.id = id; }

    public long getNoteId() { return noteId; }
    public void setNoteId(long noteId) { this.noteId = noteId; }

    public String getToken() { return token; }
    public void setToken(String token) { this.token = token; }

    public Instant getCreatedAt() { return createdAt; }
    public void setCreatedAt(Instant createdAt) { this.createdAt = createdAt; }

    @Override
    public String toString() {
        return "ShareLink{id=" + id + ", noteId=" + noteId + '}';
    }
}
